namespace sv_c00d1f9bb999491cb05462ac58e825f8.Services;

public enum ThemeMode { Light, Dark, System }

/// <summary>
/// Scoped service — one instance per circuit (interactive) or per request (static SSR).
/// With enhanced navigation the circuit persists across page navigations,
/// so all interactive components share the same instance for the lifetime of the tab.
/// </summary>
public sealed class ThemeService
{
    public ThemeMode Theme { get; private set; } = ThemeMode.System;
    public string AccentColor { get; private set; } = "#0d6efd"; // Bootstrap primary

    /// <summary>Fired whenever Theme or AccentColor changes.</summary>
    public event Action? OnChange;

    public void SetTheme(ThemeMode theme)
    {
        if (Theme == theme) return;
        Theme = theme;
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        OnChange?.Invoke();
    }
}

@* Interactive island embedded in the static layout so it can react to theme changes. *@
@rendermode InteractiveServer
@inject ThemeService ThemeSvc
@implements IDisposable

<span class="theme-indicator badge" style="background-color: @ThemeSvc.AccentColor;">
    @ThemeSvc.Theme
</span>

@code {
    protected override void OnInitialized()
        => ThemeSvc.OnChange += StateHasChanged;

    public void Dispose()
        => ThemeSvc.OnChange -= StateHasChanged;
}

@* Reusable toggle — drop it into the sidebar, a settings page, anywhere. *@
@rendermode InteractiveServer
@inject ThemeService ThemeSvc
@implements IDisposable

<button class="btn btn-sm btn-outline-secondary" @onclick="Cycle">
    🎨 @ThemeSvc.Theme
</button>

@code {
    private void Cycle()
    {
        var next = ThemeSvc.Theme switch
        {
            ThemeMode.Light  => ThemeMode.Dark,
            ThemeMode.Dark   => ThemeMode.System,
            _                => ThemeMode.Light,
        };
        ThemeSvc.SetTheme(next);
    }

    protected override void OnInitialized()
        => ThemeSvc.OnChange += StateHasChanged;

    public void Dispose()
        => ThemeSvc.OnChange -= StateHasChanged;
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeSvc
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select w-auto" @onchange="OnThemeChanged" value="@ThemeSvc.Theme">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <option value="@mode" selected="@(mode == ThemeSvc.Theme)">@mode</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@ThemeSvc.AccentColor"
           @onchange="OnColorChanged" />
</div>

<p>
    Current: <strong>@ThemeSvc.Theme</strong> /
    <span style="color: @ThemeSvc.AccentColor;">@ThemeSvc.AccentColor</span>
</p>

@code {
    private void OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<ThemeMode>(e.Value?.ToString(), out var mode))
            ThemeSvc.SetTheme(mode);
    }

    private void OnColorChanged(ChangeEventArgs e)
        => ThemeSvc.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");

    protected override void OnInitialized()
        => ThemeSvc.OnChange += StateHasChanged;

    public void Dispose()
        => ThemeSvc.OnChange -= StateHasChanged;
}

